body {
    margin: 0;
    font-family: Arial, sans-serif;
}

/* HERO */
.hero {
    background: linear-gradient(to right, #141e30, #243b55);
    color: white;
    text-align: center;
    padding: 100px 20px;
}

.hero h1 {
    font-size: 48px;
}

.hero p {
    font-size: 20px;
    margin-bottom: 20px;
}

/* BOTÕES */
button {
    background: linear-gradient(45deg, #ff7e5f, #ff4d6d);
    border: none;
    padding: 14px 24px;
    color: white;
    font-size: 16px;
    border-radius: 10px;
    cursor: pointer;
    transition: 0.3s;
}

button:hover {
    transform: scale(1.05);
}

/* SEÇÕES */
section {
    padding: 60px 20px;
    text-align: center;
}

.sobre {
    background-color: #f5f5f5;
}

.servicos {
    background-color: #ffffff;
}

.cta {
    background: #111;
    color: white;
}

.hero {
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 40px;

    background: linear-gradient(to right, #141e30, #243b55);
    color: white;
    padding: 100px 20px;
}

.hero-text {
    max-width: 400px;
    text-align: left;
}

.hero-image img {
    width: 300px;
    border-radius: 12px;
}

.btn-whatsapp {
    background-color: #25D366;
    color: white;
    padding: 14px 24px;
    border-radius: 10px;
    text-decoration: none;
    display: inline-block;
    font-size: 16px;
    font-weight: bold;
    transition: 0.3s;
}

.btn-whatsapp:hover {
    background-color: #1ebe5d;
    transform: scale(1.05);
}

.hero-text a {
    margin-top: 10px;
}

@media (max-width: 768px) {

    .hero {
        flex-direction: column;
        text-align: center;
    }

    .hero-text {
        text-align: center;
    }

    .hero-image img {
        width: 200px;
    }

    h1 {
        font-size: 32px;
    }

    p {
        font-size: 16px;
    }

}
